Javascript.validate:
//Date picker: error message “The value does not conform to a valid date format of DD-MMM-YYYY”.
//Validation: Date cannot be in the future
var err = null;
var isFuture = isFutureDate(Services.getValue(AffidavitSupportDate.dataBinding));
if( null != isFuture && isFuture )
{ err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
}
return err;
